/**
 * SPEC-036: card "Asistente en vivo" de Ajustes (componente aislado; frontera
 * de mocking: window.api.db.getAssistantSettings/setAssistantSettings) —
 * Select de tamaño de cola con default 3, precarga del valor persistido y
 * guardado inmediato con Toast «Ajustes guardados».
 * Generated by QA Dev agent.
 */
import { render, screen, waitFor, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { Toaster } from '@/components/ui/sonner'
import { AssistantSettingsCard } from '@/components/settings/AssistantSettingsCard'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

let mockApi: MockApiHandle

function renderCard(): RenderResult {
  return render(
    <>
      <AssistantSettingsCard />
      <Toaster />
    </>
  )
}

async function findQueueSizeSelect(): Promise<HTMLElement> {
  const trigger = await screen.findByRole('combobox', { name: 'Tamaño de la cola de preguntas' })
  // Disabled mientras precarga: esperar a que el get resuelva (lección tooltip/disabled)
  await waitFor(() => expect(trigger).toBeEnabled())
  return trigger
}

beforeEach(() => {
  vi.clearAllMocks()
  mockApi = installMockApi()
  vi.mocked(mockApi.api.db.setAssistantSettings).mockResolvedValue({
    ok: true,
    data: { queueSize: 5 }
  })
})

describe('AssistantSettingsCard', () => {
  // SPEC-036 · AC-15 (control con el valor 3 por defecto en «Claves de IA»)
  it('renders the "Asistente en vivo" card with the queue size select defaulting to 3', async () => {
    renderCard()

    expect(await screen.findByText('Asistente en vivo')).toBeInTheDocument()
    expect(
      screen.getByText(
        'Número máximo de preguntas pendientes visibles a la vez durante la entrevista.'
      )
    ).toBeInTheDocument()
    const trigger = await findQueueSizeSelect()
    // El almacén sin dato viaja normalizado desde main como default 3
    expect(trigger).toHaveTextContent('3')
    expect(screen.getByTestId('assistant-queue-size-select')).toBe(trigger)
  })

  // SPEC-036 · AC-15 (refuerzo: precarga del valor persistido distinto de 3)
  it('preloads a persisted queue size different from the default', async () => {
    vi.mocked(mockApi.api.db.getAssistantSettings).mockResolvedValue({
      ok: true,
      data: { queueSize: 4 }
    })
    renderCard()

    const trigger = await findQueueSizeSelect()
    expect(trigger).toHaveTextContent('4')
  })

  // SPEC-036 · AC-16 (guardado inmediato al seleccionar + Toast de confirmación)
  it('saves the selected size immediately and shows the "Ajustes guardados" toast', async () => {
    const user = userEvent.setup()
    renderCard()
    const trigger = await findQueueSizeSelect()

    await user.click(trigger)
    await user.click(await screen.findByRole('option', { name: '5' }))

    // El Select ES el commit: se persiste el entero sin botón Guardar
    expect(vi.mocked(mockApi.api.db.setAssistantSettings)).toHaveBeenCalledWith({ queueSize: 5 })
    expect((await screen.findAllByText('Ajustes guardados')).length).toBeGreaterThanOrEqual(1)
    expect(screen.getByTestId('assistant-queue-size-select')).toHaveTextContent('5')
  })
})
